import { STAR_TYPES, PLANET_TYPES } from '../constants';
import { randomColor } from '../utils/color';
import { mulberry32, hashString } from './prng';
import { generateSystemName, pickPlanetName, pickMoonName } from './names';

export function generateRandomSystem(seedStr, complexity, allowBinary, allowBelts) {
    const seed = typeof seedStr === 'string' && seedStr.length > 0 ? hashString(seedStr) : Date.now();
    const rng = mulberry32(seed);
    const actualSeed = seedStr || seed.toString();

    // Star type weighted by realism
    const starTypeWeights = { M: 0.35, K: 0.25, G: 0.15, F: 0.1, A: 0.07, B: 0.05, O: 0.03 };
    const starTypes = Object.keys(starTypeWeights);
    let roll = rng();
    let cumul = 0;
    let chosenStarType = 'G';
    for (const st of starTypes) {
        cumul += starTypeWeights[st];
        if (roll < cumul) { chosenStarType = st; break; }
    }

    const starDef = STAR_TYPES[chosenStarType];
    const starMass = +(starDef.massRange[0] + rng() * (starDef.massRange[1] - starDef.massRange[0])).toFixed(2);

    const config = {
        star: { type: chosenStarType, mass: starMass },
        binaryStar: null,
        planets: [],
        belts: []
    };

    // Binary star
    if (allowBinary && rng() < 0.25) {
        const sec_roll = rng();
        let secType = chosenStarType;
        const typeOrder = ['O', 'B', 'A', 'F', 'G', 'K', 'M'];
        const idx = typeOrder.indexOf(chosenStarType);
        if (sec_roll < 0.5 && idx < typeOrder.length - 1) {
            secType = typeOrder[idx + 1 + Math.floor(rng() * (typeOrder.length - idx - 1))];
        }
        const secDef = STAR_TYPES[secType];
        const secMass = +(secDef.massRange[0] + rng() * (secDef.massRange[1] - secDef.massRange[0])).toFixed(2);
        config.binaryStar = {
            type: secType,
            mass: secMass,
            separation: +(0.1 + rng() * 2).toFixed(1)
        };
    }

    // Number of planets
    const basePlanets = [1, 2, 4, 6, 10];
    const variance = [-1, 0, 1, 2, 3];
    const numPlanets = Math.max(1, basePlanets[complexity - 1] + Math.floor(rng() * (variance[complexity - 1] + 2)));

    // Habitable zone
    const luminosity = Math.pow(starMass, 3.5);
    const habZoneInner = Math.sqrt(luminosity) * 0.75;
    const habZoneOuter = Math.sqrt(luminosity) * 1.5;
    const frostLine = Math.sqrt(luminosity) * 2.7;

    const usedPlanetNames = new Set();
    const usedMoonNames = new Set();
    let currentDist = 0.05 + rng() * 0.2 * Math.sqrt(starMass);

    function choosePlanetType(dist) {
        if (dist < habZoneInner * 0.3) {
            return rng() < 0.6 ? 'lava' : 'hot-jupiter';
        } else if (dist < habZoneInner) {
            const types = ['rocky', 'rocky', 'super-earth', 'lava'];
            return types[Math.floor(rng() * types.length)];
        } else if (dist <= habZoneOuter) {
            const types = ['rocky', 'ocean', 'super-earth', 'rocky'];
            return types[Math.floor(rng() * types.length)];
        } else if (dist < frostLine) {
            const types = ['ice', 'super-earth', 'rocky', 'ice'];
            return types[Math.floor(rng() * types.length)];
        } else if (dist < frostLine * 3) {
            const types = ['gas-giant', 'gas-giant', 'ice-giant', 'gas-giant'];
            return types[Math.floor(rng() * types.length)];
        } else {
            const types = ['ice-giant', 'dwarf', 'ice', 'ice-giant'];
            return types[Math.floor(rng() * types.length)];
        }
    }

    const TYPE_HUES = {
        'rocky': 30, 'gas-giant': 35, 'ice-giant': 200, 'dwarf': 0,
        'super-earth': 140, 'hot-jupiter': 20, 'lava': 5, 'ocean': 210, 'ice': 210
    };
    const TYPE_SAT = {
        'rocky': [15, 40], 'gas-giant': [25, 50], 'ice-giant': [30, 60], 'dwarf': [5, 20],
        'super-earth': [25, 50], 'hot-jupiter': [50, 80], 'lava': [60, 90], 'ocean': [40, 70], 'ice': [20, 45]
    };
    const TYPE_LIGHT = {
        'rocky': [40, 65], 'gas-giant': [45, 65], 'ice-giant': [50, 70], 'dwarf': [40, 60],
        'super-earth': [35, 55], 'hot-jupiter': [45, 60], 'lava': [30, 50], 'ocean': [35, 55], 'ice': [60, 80]
    };

    let prevRadiusEarth = 0;
    for (let i = 0; i < numPlanets; i++) {
        const spacing = (0.2 + rng() * 0.6) * Math.pow(1.4 + rng() * 0.8, i);
        currentDist += spacing * Math.sqrt(starMass);

        const type = choosePlanetType(currentDist);
        const pTypeDef = PLANET_TYPES[type];
        const radiusEarth = +(pTypeDef.radiusRange[0] + rng() * (pTypeDef.radiusRange[1] - pTypeDef.radiusRange[0])).toFixed(2);

        // Ensure planets don't visually overlap: minimum AU gap based on both radii
        // Visual radius ∝ √(radiusEarth), distance in px = AU * 25 * zoom
        // Need gap in AU so that at reasonable zoom levels planets don't collide
        const minGapAU = (Math.sqrt(prevRadiusEarth) + Math.sqrt(radiusEarth)) * 0.2;
        if (i > 0 && currentDist - config.planets[i - 1].semiMajorAxis < minGapAU) {
            currentDist = config.planets[i - 1].semiMajorAxis + minGapAU;
        }

        const dist = +currentDist.toFixed(3);
        const eccentricity = +(rng() * rng() * 0.3).toFixed(3);

        const hue = TYPE_HUES[type] || 30;
        const sat = TYPE_SAT[type] || [20, 50];
        const light = TYPE_LIGHT[type] || [40, 65];
        const color = randomColor(rng, hue, sat, light);

        let hasRings = false;
        let ringInner = 1.2, ringOuter = 2.3, ringColor = '#d2be9f';
        if (type === 'gas-giant' || type === 'ice-giant' || type === 'hot-jupiter') {
            hasRings = rng() < 0.35;
        } else {
            hasRings = rng() < 0.05;
        }
        if (hasRings) {
            ringInner = +(1.1 + rng() * 0.5).toFixed(2);
            ringOuter = +(ringInner + 0.3 + rng() * 1.5).toFixed(2);
            ringColor = randomColor(rng, hue + 10, [10, 30], [50, 70]);
        }

        let numMoons = 0;
        if (type === 'gas-giant' || type === 'hot-jupiter') {
            numMoons = Math.floor(rng() * (2 + complexity)) + (complexity > 2 ? 1 : 0);
        } else if (type === 'ice-giant' || type === 'super-earth') {
            numMoons = Math.floor(rng() * (1 + complexity * 0.5));
        } else if (type === 'rocky' || type === 'ocean') {
            numMoons = rng() < 0.4 ? Math.floor(rng() * 2) : 0;
        }
        numMoons = Math.min(numMoons, 6);

        const moons = [];
        for (let m = 0; m < numMoons; m++) {
            moons.push({
                name: pickMoonName(rng, usedMoonNames),
                orbitRadius: +((0.0005 + rng() * 0.015) * (1 + m * 0.5)).toFixed(5),
                radius: +(0.02 + rng() * 0.3 * (type === 'gas-giant' ? 1.5 : 0.5)).toFixed(3),
                color: randomColor(rng, rng() * 360, [5, 25], [50, 75])
            });
        }

        config.planets.push({
            name: pickPlanetName(rng, usedPlanetNames),
            type, semiMajorAxis: dist, radiusEarth, eccentricity, color,
            hasRings, ringInner, ringOuter, ringColor, moons
        });
        prevRadiusEarth = radiusEarth;
    }

    // Asteroid belts
    if (allowBelts && complexity >= 2) {
        const numBelts = Math.min(complexity - 1, 3);
        const maxDist = config.planets.length > 0 ? config.planets[config.planets.length - 1].semiMajorAxis : 5;

        for (let b = 0; b < numBelts; b++) {
            if (rng() < 0.6 || b === 0) {
                let inner, outer;
                if (b === 0 && config.planets.length >= 2) {
                    const gapIdx = Math.floor(rng() * (config.planets.length - 1));
                    inner = config.planets[gapIdx].semiMajorAxis * (1.1 + rng() * 0.3);
                    outer = config.planets[gapIdx + 1].semiMajorAxis * (0.7 + rng() * 0.2);
                    if (outer <= inner) { outer = inner * (1.3 + rng() * 0.5); }
                } else {
                    inner = maxDist * (1.2 + rng() * 0.5);
                    outer = inner * (1.3 + rng() * 0.7);
                }
                const beltColors = ['#968c82', '#776655', '#888877', '#556677', '#665544', '#887766'];
                config.belts.push({
                    name: b === 0 ? 'Asteroid Belt' : (b === 1 ? 'Outer Belt' : 'Debris Disk'),
                    innerRadius: +inner.toFixed(1),
                    outerRadius: +outer.toFixed(1),
                    count: Math.floor(150 + rng() * 300 * complexity),
                    color: beltColors[Math.floor(rng() * beltColors.length)]
                });
            }
        }
    }

    const sysName = generateSystemName(rng);
    const info = {
        seed: actualSeed,
        name: sysName,
        starType: chosenStarType,
        starMass: starMass,
        binary: !!config.binaryStar,
        numPlanets: config.planets.length,
        numMoons: config.planets.reduce((s, p) => s + p.moons.length, 0),
        numBelts: config.belts.length,
        habZone: `${habZoneInner.toFixed(2)} - ${habZoneOuter.toFixed(2)} AU`
    };

    return { config, info };
}
