export function getPreset(name) {
    switch (name) {
        case 'solar':
            return defaultSolarSystem();
        case 'binary': {
            const cfg = defaultSolarSystem();
            cfg.binaryStar = { type: 'K', mass: 0.6, separation: 0.5 };
            return cfg;
        }
        case 'red-dwarf':
            return {
                star: { type: 'M', mass: 0.3 },
                binaryStar: null,
                planets: [
                    { name: 'Proxima b', type: 'rocky', semiMajorAxis: 0.05, radiusEarth: 1.1, eccentricity: 0.02, color: '#aa7755', hasRings: false, ringInner: 1.2, ringOuter: 2.3, ringColor: '#d2be9f', moons: [] },
                    { name: 'Proxima c', type: 'ice', semiMajorAxis: 0.15, radiusEarth: 0.8, eccentricity: 0.04, color: '#aaccee', hasRings: false, ringInner: 1.2, ringOuter: 2.3, ringColor: '#d2be9f',
                        moons: [{ name: 'Ice Moon', orbitRadius: 0.001, radius: 0.05, color: '#ccddee' }] },
                    { name: 'Proxima d', type: 'super-earth', semiMajorAxis: 0.4, radiusEarth: 2.0, eccentricity: 0.1, color: '#66aa88', hasRings: false, ringInner: 1.2, ringOuter: 2.3, ringColor: '#d2be9f', moons: [] },
                ],
                belts: [
                    { name: 'Debris Disk', innerRadius: 0.8, outerRadius: 1.5, count: 200, color: '#776655' }
                ]
            };
        case 'giant':
            return {
                star: { type: 'O', mass: 20 },
                binaryStar: null,
                planets: [
                    { name: 'Inferno', type: 'lava', semiMajorAxis: 1.0, radiusEarth: 3, eccentricity: 0.05, color: '#ff4422', hasRings: false, ringInner: 1.2, ringOuter: 2.3, ringColor: '#d2be9f', moons: [] },
                    { name: 'Colossus', type: 'hot-jupiter', semiMajorAxis: 3.0, radiusEarth: 15, eccentricity: 0.02, color: '#ff8844', hasRings: true, ringInner: 1.3, ringOuter: 2.5, ringColor: '#ffaa66',
                        moons: [
                            { name: 'Ember', orbitRadius: 0.01, radius: 0.3, color: '#cc8844' },
                            { name: 'Ash', orbitRadius: 0.02, radius: 0.15, color: '#997766' },
                        ] },
                    { name: 'Leviathan', type: 'gas-giant', semiMajorAxis: 8.0, radiusEarth: 12, eccentricity: 0.03, color: '#ccaa77', hasRings: true, ringInner: 1.2, ringOuter: 2.8, ringColor: '#ddcc99', moons: [] },
                    { name: 'Frost', type: 'ice-giant', semiMajorAxis: 20.0, radiusEarth: 5, eccentricity: 0.08, color: '#88bbee', hasRings: false, ringInner: 1.2, ringOuter: 2.3, ringColor: '#d2be9f',
                        moons: [{ name: 'Glacial', orbitRadius: 0.005, radius: 0.2, color: '#aaddff' }] },
                    { name: 'Abyss', type: 'ocean', semiMajorAxis: 35.0, radiusEarth: 2.5, eccentricity: 0.01, color: '#3388cc', hasRings: false, ringInner: 1.2, ringOuter: 2.3, ringColor: '#d2be9f', moons: [] },
                ],
                belts: [
                    { name: 'Inner Debris', innerRadius: 5, outerRadius: 6.5, count: 500, color: '#998866' },
                    { name: 'Outer Ring', innerRadius: 40, outerRadius: 55, count: 300, color: '#556677' }
                ]
            };
        default:
            return defaultSolarSystem();
    }
}
