import { state } from '../state';
import { parseColor } from '../utils/color';
import { scaleDistance } from '../utils/physics';

export function drawBelt(beltConf, objects, cx, cy, t) {
    const { ctx, zoomLevel } = state;
    const bc = parseColor(beltConf.color);
    for (const obj of objects) {
        const period = Math.pow(obj.dist, 1.5);
        const angle = obj.angle + (t / period) * Math.PI * 2 * obj.speedVar;
        const e = obj.eccentricity;
        const r = obj.dist * (1 - e * e) / (1 + e * Math.cos(angle));
        const ax = cx + scaleDistance(r * Math.cos(angle), zoomLevel);
        const ay = cy + scaleDistance(r * Math.sin(angle), zoomLevel);
        const sz = obj.size * Math.pow(zoomLevel, 0.2);

        const colorVar = ((obj.angle * 100) | 0) % 40 - 20;
        const ar = Math.min(255, Math.max(0, bc.r + colorVar));
        const ag = Math.min(255, Math.max(0, bc.g + colorVar));
        const ab = Math.min(255, Math.max(0, bc.b + colorVar));
        const alpha = 0.3 + obj.size * 0.2;
        ctx.fillStyle = `rgba(${ar},${ag},${ab},${alpha})`;
        ctx.beginPath();
        ctx.arc(ax, ay, sz, 0, Math.PI * 2);
        ctx.fill();
    }
}
