import { h } from 'preact';
import { useState, useEffect, useRef } from 'preact/hooks';
import { state } from '../state';
import { saveScreenshot } from '../render/renderer';
import { scaleDistance } from '../utils/physics';
import { InfoPanel } from './InfoPanel';

export function Controls() {
    const [speedLabel, setSpeedLabel] = useState('1.0x');
    const [zoomLabel, setZoomLabel] = useState('1.0x');
    const [following, setFollowing] = useState(null);
    const [collapsed, setCollapsed] = useState(false);
    const speedRef = useRef(null);
    const zoomRef = useRef(null);

    useEffect(() => {
        const canvas = state.canvas;
        let lastPinchDist = 0;

        const minZoom = () => {
            let maxAU = 1;
            for (const p of state.systemConfig.planets) {
                const d = p.semiMajorAxis * (1 + (p.eccentricity || 0));
                if (d > maxAU) maxAU = d;
            }
            const minDim = Math.min(state.width, state.height);
            return minDim > 0 ? Math.max(0.02, minDim / (maxAU * 25 * 4)) : 0.02;
        };

        const updateZoomUI = () => {
            if (zoomRef.current) zoomRef.current.value = state.zoomLevel * 50;
            setZoomLabel(state.zoomLevel.toFixed(1) + 'x');
        };

        // --- Mouse events ---
        const onWheel = (e) => {
            e.preventDefault();
            const delta = e.deltaY > 0 ? 0.9 : 1.1;
            state.zoomLevel = Math.max(minZoom(), Math.min(10, state.zoomLevel * delta));
            updateZoomUI();
        };

        const onMouseDown = (e) => {
            state.isPanning = true;
            state.lastMouse.x = e.clientX;
            state.lastMouse.y = e.clientY;
        };

        const onMouseMove = (e) => {
            if (state.isPanning) {
                if (state.followTarget) {
                    state.followTarget = null;
                    setFollowing(null);
                }
                state.panX += e.clientX - state.lastMouse.x;
                state.panY += e.clientY - state.lastMouse.y;
                state.lastMouse.x = e.clientX;
                state.lastMouse.y = e.clientY;
            }
            state.hoveredBody = null;
            for (const body of state.bodies) {
                const dx = e.clientX - body.x;
                const dy = e.clientY - body.y;
                if (Math.sqrt(dx * dx + dy * dy) < body.r + 5) {
                    state.hoveredBody = body;
                    canvas.style.cursor = 'pointer';
                    break;
                }
            }
            if (!state.hoveredBody && !state.isPanning) canvas.style.cursor = 'grab';
        };

        const onClick = (e) => {
            for (const body of state.bodies) {
                const dx = e.clientX - body.x;
                const dy = e.clientY - body.y;
                if (Math.sqrt(dx * dx + dy * dy) < body.r + 5) {
                    state.selectedBody = body;
                    return;
                }
            }
            state.selectedBody = null;
            state.followTarget = null;
            setFollowing(null);
        };

        const onMouseUp = () => { state.isPanning = false; };
        const onMouseLeave = () => { state.isPanning = false; };

        // --- Touch events ---
        const onTouchStart = (e) => {
            e.preventDefault();
            if (e.touches.length === 1) {
                state.isPanning = true;
                state.lastMouse.x = e.touches[0].clientX;
                state.lastMouse.y = e.touches[0].clientY;
            } else if (e.touches.length === 2) {
                state.isPanning = false;
                const dx = e.touches[0].clientX - e.touches[1].clientX;
                const dy = e.touches[0].clientY - e.touches[1].clientY;
                lastPinchDist = Math.sqrt(dx * dx + dy * dy);
            }
        };

        const onTouchMove = (e) => {
            e.preventDefault();
            if (e.touches.length === 1 && state.isPanning) {
                const tx = e.touches[0].clientX;
                const ty = e.touches[0].clientY;
                if (state.followTarget) {
                    state.followTarget = null;
                    setFollowing(null);
                }
                state.panX += tx - state.lastMouse.x;
                state.panY += ty - state.lastMouse.y;
                state.lastMouse.x = tx;
                state.lastMouse.y = ty;
            } else if (e.touches.length === 2) {
                const dx = e.touches[0].clientX - e.touches[1].clientX;
                const dy = e.touches[0].clientY - e.touches[1].clientY;
                const dist = Math.sqrt(dx * dx + dy * dy);
                if (lastPinchDist > 0) {
                    const scale = dist / lastPinchDist;
                    state.zoomLevel = Math.max(minZoom(), Math.min(10, state.zoomLevel * scale));
                    updateZoomUI();
                }
                lastPinchDist = dist;
            }
        };

        const onTouchEnd = (e) => {
            if (e.touches.length < 2) lastPinchDist = 0;
            if (e.touches.length === 0) {
                // Tap to select (only if didn't move much)
                if (state.isPanning && e.changedTouches.length === 1) {
                    const tx = e.changedTouches[0].clientX;
                    const ty = e.changedTouches[0].clientY;
                    const moved = Math.abs(tx - state.lastMouse.x) + Math.abs(ty - state.lastMouse.y);
                    // Only treat as tap if barely moved (threshold for tap vs drag)
                    const startX = state.lastMouse.x;
                    const startY = state.lastMouse.y;
                    if (moved < 10) {
                        for (const body of state.bodies) {
                            const dx = tx - body.x;
                            const dy = ty - body.y;
                            if (Math.sqrt(dx * dx + dy * dy) < body.r + 12) {
                                state.selectedBody = body;
                                state.isPanning = false;
                                return;
                            }
                        }
                        state.selectedBody = null;
                        state.followTarget = null;
                        setFollowing(null);
                    }
                }
                state.isPanning = false;
            }
        };

        canvas.addEventListener('wheel', onWheel, { passive: false });
        canvas.addEventListener('mousedown', onMouseDown);
        canvas.addEventListener('mousemove', onMouseMove);
        canvas.addEventListener('mouseup', onMouseUp);
        canvas.addEventListener('mouseleave', onMouseLeave);
        canvas.addEventListener('click', onClick);
        canvas.addEventListener('touchstart', onTouchStart, { passive: false });
        canvas.addEventListener('touchmove', onTouchMove, { passive: false });
        canvas.addEventListener('touchend', onTouchEnd);

        return () => {
            canvas.removeEventListener('wheel', onWheel);
            canvas.removeEventListener('mousedown', onMouseDown);
            canvas.removeEventListener('mousemove', onMouseMove);
            canvas.removeEventListener('mouseup', onMouseUp);
            canvas.removeEventListener('mouseleave', onMouseLeave);
            canvas.removeEventListener('click', onClick);
            canvas.removeEventListener('touchstart', onTouchStart);
            canvas.removeEventListener('touchmove', onTouchMove);
            canvas.removeEventListener('touchend', onTouchEnd);
        };
    }, []);

    const zoomToBody = (body) => {
        if (!body) return;
        state.panX = state.centerX - body.x + state.panX;
        state.panY = state.centerY - body.y + state.panY;
        const targetZoom = Math.min(10, Math.max(2, 20 / Math.max(body.r, 5)));
        state.zoomLevel = targetZoom;
        if (zoomRef.current) zoomRef.current.value = targetZoom * 50;
        setZoomLabel(targetZoom.toFixed(1) + 'x');
    };

    const followBody = (body) => {
        if (!body) return;
        if (state.followTarget === body.name) {
            state.followTarget = null;
            setFollowing(null);
        } else {
            state.followTarget = body.name;
            setFollowing(body.name);
            const targetZoom = Math.min(10, Math.max(2, 20 / Math.max(body.r, 5)));
            state.zoomLevel = targetZoom;
            if (zoomRef.current) zoomRef.current.value = targetZoom * 50;
            setZoomLabel(targetZoom.toFixed(1) + 'x');
        }
    };

    const resetView = () => {
        state.panX = 0;
        state.panY = 0;
        state.zoomLevel = 1;
        state.followTarget = null;
        setFollowing(null);
        if (zoomRef.current) zoomRef.current.value = 50;
        setZoomLabel('1.0x');
    };

    return h('div', { id: 'controls', class: collapsed ? 'controls-collapsed' : '' },
        h('button', {
            id: 'controls-toggle',
            onClick: () => setCollapsed(!collapsed)
        }, collapsed ? '\u25BC' : '\u25B2'),
        !collapsed && h('div', { class: 'controls-body' },
            h('div', { class: 'control-group' },
                h('label', null, 'Speed: ', h('span', null, speedLabel)),
                h('input', {
                    type: 'range', ref: speedRef, min: 0, max: 100, value: 10,
                    onInput: (e) => {
                        state.speedMultiplier = Math.pow(e.target.value / 10, 2);
                        setSpeedLabel(state.speedMultiplier.toFixed(1) + 'x');
                    }
                })
            ),
            h('div', { class: 'control-group' },
                h('label', null, 'Zoom: ', h('span', null, zoomLabel)),
                h('input', {
                    type: 'range', ref: zoomRef, min: 1, max: 500, value: 50,
                    onInput: (e) => {
                        state.zoomLevel = e.target.value / 50;
                        setZoomLabel(state.zoomLevel.toFixed(1) + 'x');
                    }
                })
            ),
            h('div', { class: 'control-row-compact' },
                h('label', null,
                    h('input', {
                        type: 'checkbox', checked: true,
                        onChange: (e) => { state.showOrbits = e.target.checked; }
                    }),
                    ' Orbits'
                ),
                h('label', null,
                    h('input', {
                        type: 'checkbox', checked: true,
                        onChange: (e) => { state.showLabels = e.target.checked; }
                    }),
                    ' Labels'
                )
            ),
            h('div', { class: 'control-btn-row' },
                h('button', { class: 'btn btn-screenshot', onClick: saveScreenshot }, '\uD83D\uDCF7'),
                h('button', { class: 'btn btn-screenshot', onClick: resetView }, '\uD83C\uDFE0 Reset')
            ),
            following && h('div', { class: 'follow-indicator' },
                'Following: ', h('strong', null, following),
                h('button', { class: 'btn btn-small', style: 'margin-left:6px', onClick: () => { state.followTarget = null; setFollowing(null); } }, '\u2715')
            ),
            h(InfoPanel, { onZoomTo: zoomToBody, onFollow: followBody, following })
        )
    );
}
