import { STAR_TYPES } from '../constants';

export function scaleDistance(au, zoomLevel) {
    return au * 25 * zoomLevel;
}

export function scaleRadius(earthRadii, zoomLevel) {
    const base = Math.sqrt(earthRadii) * 3.5 * Math.pow(zoomLevel, 0.3);
    return Math.max(1.5, base);
}

export function sunVisualRadius(mass, starType, zoomLevel) {
    const st = STAR_TYPES[starType];
    const factor = st.radiusFactor * Math.pow(mass, 0.5);
    return Math.max(8, factor * 8 * Math.pow(zoomLevel, 0.3));
}

export function getOrbitalPosition(semiMajorAxis, eccentricity, period, t) {
    const angle = (t / period) * Math.PI * 2;
    const e = eccentricity || 0;
    const M = angle;
    const E = M + e * Math.sin(M);
    const trueAnomaly = 2 * Math.atan2(
        Math.sqrt(1 + e) * Math.sin(E / 2),
        Math.sqrt(1 - e) * Math.cos(E / 2)
    );
    const r = semiMajorAxis * (1 - e * e) / (1 + e * Math.cos(trueAnomaly));
    return { x: r * Math.cos(trueAnomaly), y: r * Math.sin(trueAnomaly) };
}
