import { state } from '../state';
import { scaleDistance } from '../utils/physics';

export function drawOrbit(cx, cy, semiMajorAU, eccentricity) {
    if (!state.showOrbits) return;
    const { ctx, zoomLevel } = state;
    const a = scaleDistance(semiMajorAU, zoomLevel);
    const e = eccentricity || 0;
    const b = a * Math.sqrt(1 - e * e);
    const focusOffset = a * e;
    ctx.save();
    ctx.strokeStyle = 'rgba(255,255,255,0.07)';
    ctx.lineWidth = 0.7;
    ctx.setLineDash([4, 6]);
    ctx.beginPath();
    ctx.ellipse(cx - focusOffset, cy, a, b, 0, 0, Math.PI * 2);
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();
}
