import { h } from 'preact';
import { useState, useEffect } from 'preact/hooks';
import { PLANET_TYPES } from '../constants';
import { state } from '../state';

export function PlanetModal({ planetIdx, onClose, onSave }) {
    const isNew = planetIdx < 0;
    const existing = !isNew ? state.systemConfig.planets[planetIdx] : null;

    const [name, setName] = useState(existing ? existing.name : 'New Planet');
    const [type, setType] = useState(existing ? existing.type : 'rocky');
    const [color, setColor] = useState(existing ? existing.color : '#b0a090');
    const [dist, setDist] = useState(existing ? existing.semiMajorAxis : 2);
    const [radius, setRadius] = useState(existing ? existing.radiusEarth : 1);
    const [ecc, setEcc] = useState(existing ? existing.eccentricity : 0.01);
    const [hasRings, setHasRings] = useState(existing ? existing.hasRings : false);
    const [ringInner, setRingInner] = useState(existing ? existing.ringInner : 1.2);
    const [ringOuter, setRingOuter] = useState(existing ? existing.ringOuter : 2.3);
    const [ringColor, setRingColor] = useState(existing ? (existing.ringColor || '#d2be9f') : '#d2be9f');
    const [moons, setMoons] = useState(existing ? existing.moons.map(m => ({ ...m })) : []);

    const addMoon = () => {
        setMoons([...moons, { name: 'Moon', orbitRadius: 0.003, radius: 0.1, color: '#aaaaaa' }]);
    };

    const removeMoon = (idx) => {
        setMoons(moons.filter((_, i) => i !== idx));
    };

    const updateMoon = (idx, field, value) => {
        const updated = [...moons];
        updated[idx] = { ...updated[idx], [field]: value };
        setMoons(updated);
    };

    const handleSave = () => {
        const planet = {
            name, type, color,
            semiMajorAxis: parseFloat(dist),
            radiusEarth: parseFloat(radius),
            eccentricity: parseFloat(ecc),
            hasRings,
            ringInner: parseFloat(ringInner),
            ringOuter: parseFloat(ringOuter),
            ringColor,
            moons: moons.map(m => ({
                ...m,
                orbitRadius: parseFloat(m.orbitRadius),
                radius: parseFloat(m.radius)
            }))
        };
        onSave(planet, planetIdx);
    };

    const handleTypeChange = (newType) => {
        setType(newType);
        const ptype = PLANET_TYPES[newType];
        if (ptype) setColor(ptype.defaultColor);
    };

    return h('div', { class: 'modal', onClick: (e) => { if (e.target.classList.contains('modal')) onClose(); } },
        h('div', { class: 'modal-content' },
            h('h3', null, isNew ? 'Add Planet' : 'Edit Planet'),
            h('div', { class: 'modal-body' },
                h('div', { class: 'field' },
                    h('label', null, 'Name'),
                    h('input', { type: 'text', value: name, onInput: (e) => setName(e.target.value) })
                ),
                h('div', { class: 'field-row' },
                    h('div', { class: 'field' },
                        h('label', null, 'Type'),
                        h('select', { value: type, onChange: (e) => handleTypeChange(e.target.value) },
                            h('option', { value: 'rocky' }, 'Rocky (Terrestrial)'),
                            h('option', { value: 'gas-giant' }, 'Gas Giant'),
                            h('option', { value: 'ice-giant' }, 'Ice Giant'),
                            h('option', { value: 'dwarf' }, 'Dwarf Planet'),
                            h('option', { value: 'super-earth' }, 'Super-Earth'),
                            h('option', { value: 'hot-jupiter' }, 'Hot Jupiter'),
                            h('option', { value: 'lava' }, 'Lava World'),
                            h('option', { value: 'ocean' }, 'Ocean World'),
                            h('option', { value: 'ice' }, 'Ice World')
                        )
                    ),
                    h('div', { class: 'field' },
                        h('label', null, 'Color'),
                        h('input', { type: 'color', value: color, onInput: (e) => setColor(e.target.value) })
                    )
                ),
                h('div', { class: 'field' },
                    h('label', null, `Orbit Distance (AU): ${dist}`),
                    h('input', { type: 'range', min: 0.05, max: 60, step: 0.05, value: dist, onInput: (e) => setDist(e.target.value) })
                ),
                h('div', { class: 'field' },
                    h('label', null, `Radius (Earth radii): ${radius}`),
                    h('input', { type: 'range', min: 0.1, max: 20, step: 0.1, value: radius, onInput: (e) => setRadius(e.target.value) })
                ),
                h('div', { class: 'field' },
                    h('label', null, `Eccentricity: ${ecc}`),
                    h('input', { type: 'range', min: 0, max: 0.9, step: 0.01, value: ecc, onInput: (e) => setEcc(e.target.value) })
                ),
                h('div', { class: 'field' },
                    h('label', null,
                        h('input', { type: 'checkbox', checked: hasRings, onChange: (e) => setHasRings(e.target.checked) }),
                        ' Has Rings'
                    )
                ),
                hasRings && h('div', null,
                    h('div', { class: 'field' },
                        h('label', null, `Ring Inner (planet radii): ${ringInner}`),
                        h('input', { type: 'range', min: 1.1, max: 2, step: 0.05, value: ringInner, onInput: (e) => setRingInner(e.target.value) })
                    ),
                    h('div', { class: 'field' },
                        h('label', null, `Ring Outer (planet radii): ${ringOuter}`),
                        h('input', { type: 'range', min: 1.5, max: 4, step: 0.05, value: ringOuter, onInput: (e) => setRingOuter(e.target.value) })
                    ),
                    h('div', { class: 'field' },
                        h('label', null, 'Ring Color'),
                        h('input', { type: 'color', value: ringColor, onInput: (e) => setRingColor(e.target.value) })
                    )
                ),
                h('h4', null, 'Moons'),
                moons.map((moon, i) =>
                    h('div', { class: 'moon-card', key: i },
                        h('input', { type: 'text', class: 'moon-name', value: moon.name, onInput: (e) => updateMoon(i, 'name', e.target.value) }),
                        h('input', { type: 'range', class: 'moon-orbit', min: 0.0001, max: 0.05, step: 0.0001, value: moon.orbitRadius, onInput: (e) => updateMoon(i, 'orbitRadius', e.target.value) }),
                        h('input', { type: 'range', class: 'moon-radius', min: 0.01, max: 1, step: 0.01, value: moon.radius, onInput: (e) => updateMoon(i, 'radius', e.target.value) }),
                        h('input', { type: 'color', class: 'moon-color', value: moon.color, onInput: (e) => updateMoon(i, 'color', e.target.value) }),
                        h('button', { class: 'moon-del', onClick: () => removeMoon(i) }, '\u00D7')
                    )
                ),
                h('button', { class: 'btn btn-add btn-small', onClick: addMoon }, '+ Add Moon')
            ),
            h('div', { class: 'modal-footer' },
                h('button', { class: 'btn', onClick: onClose }, 'Cancel'),
                h('button', { class: 'btn btn-primary', onClick: handleSave }, 'Save')
            )
        )
    );
}
