import { h } from 'preact';
import { useState, useCallback } from 'preact/hooks';
import { COMPLEXITY_LABELS } from '../constants';
import { state } from '../state';
import { getPreset } from '../data/defaults';
import { generateRandomSystem } from '../generator/randomizer';
import { regenerateBelts } from '../render/renderer';
import { PlanetModal } from './PlanetModal';

function Section({ id, title, children }) {
    const [collapsed, setCollapsed] = useState(false);
    return h('div', { class: 'editor-section' },
        h('h4', { class: 'section-header', onClick: () => setCollapsed(!collapsed) },
            title, ' ', h('span', { class: 'toggle-icon' }, collapsed ? '\u25B6' : '\u25BC')
        ),
        !collapsed && h('div', { class: 'section-body' }, children)
    );
}

export function EditorPanel({ open, onClose }) {
    const [, forceUpdate] = useState(0);
    const refresh = useCallback(() => forceUpdate(n => n + 1), []);

    // Star state
    const [starType, setStarType] = useState(state.systemConfig.star.type);
    const [starMass, setStarMass] = useState(state.systemConfig.star.mass);
    const [binaryEnabled, setBinaryEnabled] = useState(!!state.systemConfig.binaryStar);
    const [star2Type, setStar2Type] = useState(state.systemConfig.binaryStar?.type || 'K');
    const [star2Mass, setStar2Mass] = useState(state.systemConfig.binaryStar?.mass || 0.5);
    const [binarySep, setBinarySep] = useState(state.systemConfig.binaryStar?.separation || 0.5);

    // Modal
    const [modalIdx, setModalIdx] = useState(null);

    // Randomizer
    const [seed, setSeed] = useState('');
    const [complexity, setComplexity] = useState(3);
    const [allowBinary, setAllowBinary] = useState(false);
    const [allowBelts, setAllowBelts] = useState(true);
    const [randomInfo, setRandomInfo] = useState(null);

    const syncFromState = () => {
        setStarType(state.systemConfig.star.type);
        setStarMass(state.systemConfig.star.mass);
        setBinaryEnabled(!!state.systemConfig.binaryStar);
        if (state.systemConfig.binaryStar) {
            setStar2Type(state.systemConfig.binaryStar.type);
            setStar2Mass(state.systemConfig.binaryStar.mass);
            setBinarySep(state.systemConfig.binaryStar.separation);
        }
        refresh();
    };

    const applyStar = () => {
        state.systemConfig.star.type = starType;
        state.systemConfig.star.mass = parseFloat(starMass);
        if (binaryEnabled) {
            state.systemConfig.binaryStar = {
                type: star2Type,
                mass: parseFloat(star2Mass),
                separation: parseFloat(binarySep)
            };
        } else {
            state.systemConfig.binaryStar = null;
        }
    };

    const loadPresetAndSync = (name) => {
        state.systemConfig = getPreset(name);
        regenerateBelts();
        syncFromState();
    };

    const deletePlanet = (idx) => {
        state.systemConfig.planets.splice(idx, 1);
        refresh();
    };

    const handlePlanetSave = (planet, idx) => {
        if (idx >= 0) {
            state.systemConfig.planets[idx] = planet;
        } else {
            state.systemConfig.planets.push(planet);
        }
        setModalIdx(null);
        refresh();
    };

    // Belt handlers
    const addBelt = () => {
        state.systemConfig.belts.push({
            name: 'Belt ' + (state.systemConfig.belts.length + 1),
            innerRadius: 4, outerRadius: 6, count: 300, color: '#888877'
        });
        regenerateBelts();
        refresh();
    };

    const deleteBelt = (idx) => {
        state.systemConfig.belts.splice(idx, 1);
        state.beltObjects.splice(idx, 1);
        refresh();
    };

    const updateBelt = (idx, field, value) => {
        state.systemConfig.belts[idx][field] = field === 'count' ? parseInt(value) : parseFloat(value);
        regenerateBelts();
        refresh();
    };

    const doRandomize = () => {
        const { config, info } = generateRandomSystem(seed, complexity, allowBinary, allowBelts);
        state.systemConfig = config;
        regenerateBelts();
        setSeed(info.seed);
        setRandomInfo(info);
        syncFromState();
    };

    const starTypeOptions = [
        ['G', 'G (Yellow - like Sun)'], ['O', 'O (Blue Giant)'], ['B', 'B (Blue-White)'],
        ['A', 'A (White)'], ['F', 'F (Yellow-White)'], ['K', 'K (Orange Dwarf)'], ['M', 'M (Red Dwarf)']
    ];

    return h('div', { id: 'editor-panel', class: open ? '' : 'panel-collapsed' },
        h('div', { id: 'editor-content' },
            h('div', { class: 'editor-title-row' },
                h('h3', null, 'System Editor'),
                h('button', { id: 'editor-close', onClick: onClose }, '\u2715')
            ),

            // Stars
            h(Section, { id: 'star-config', title: '\u2733 Stars' },
                h('div', { class: 'field' },
                    h('label', null, 'Star Type'),
                    h('select', { value: starType, onChange: (e) => setStarType(e.target.value) },
                        starTypeOptions.map(([v, l]) => h('option', { value: v, key: v }, l))
                    )
                ),
                h('div', { class: 'field' },
                    h('label', null, `Star Mass (Solar masses): ${parseFloat(starMass).toFixed(1)}`),
                    h('input', { type: 'range', min: 0.1, max: 50, step: 0.1, value: starMass, onInput: (e) => setStarMass(e.target.value) })
                ),
                h('div', { class: 'field' },
                    h('label', null,
                        h('input', { type: 'checkbox', checked: binaryEnabled, onChange: (e) => setBinaryEnabled(e.target.checked) }),
                        ' Binary Star System'
                    )
                ),
                binaryEnabled && h('div', null,
                    h('div', { class: 'field' },
                        h('label', null, 'Secondary Star Type'),
                        h('select', { value: star2Type, onChange: (e) => setStar2Type(e.target.value) },
                            starTypeOptions.map(([v, l]) => h('option', { value: v, key: v }, l))
                        )
                    ),
                    h('div', { class: 'field' },
                        h('label', null, `Secondary Mass: ${parseFloat(star2Mass).toFixed(1)}`),
                        h('input', { type: 'range', min: 0.1, max: 50, step: 0.1, value: star2Mass, onInput: (e) => setStar2Mass(e.target.value) })
                    ),
                    h('div', { class: 'field' },
                        h('label', null, `Binary Separation (AU): ${parseFloat(binarySep).toFixed(1)}`),
                        h('input', { type: 'range', min: 0.1, max: 5, step: 0.1, value: binarySep, onInput: (e) => setBinarySep(e.target.value) })
                    )
                ),
                h('button', { class: 'btn', onClick: applyStar }, 'Apply Star Changes')
            ),

            // Planets
            h(Section, { id: 'planet-list', title: '\uD83C\uDF0F Planets' },
                state.systemConfig.planets.map((p, i) =>
                    h('div', { class: 'planet-card', key: i },
                        h('div', { class: 'planet-swatch', style: `background:${p.color}` }),
                        h('div', { class: 'planet-info' },
                            h('div', { class: 'planet-card-name' }, p.name),
                            h('div', { class: 'planet-card-detail' }, `${p.type} | ${p.semiMajorAxis} AU | ${p.moons.length} moon(s)`)
                        ),
                        h('div', { class: 'planet-actions' },
                            h('button', { onClick: (e) => { e.stopPropagation(); setModalIdx(i); }, title: 'Edit' }, '\u270E'),
                            h('button', { class: 'btn-danger', onClick: (e) => { e.stopPropagation(); deletePlanet(i); }, title: 'Delete' }, '\u2715')
                        )
                    )
                ),
                h('button', { class: 'btn btn-add', onClick: () => setModalIdx(-1) }, '+ Add Planet')
            ),

            // Belts
            h(Section, { id: 'belts-config', title: '\u263C Asteroid Belts' },
                state.systemConfig.belts.map((belt, i) =>
                    h('div', { class: 'belt-card', key: i },
                        h('div', { class: 'belt-header' },
                            h('span', null, belt.name),
                            h('button', { class: 'btn btn-danger btn-small', onClick: () => deleteBelt(i) }, '\u00D7')
                        ),
                        h('div', { class: 'field' },
                            h('label', null, `Inner (AU): ${belt.innerRadius}`),
                            h('input', { type: 'range', min: 0.1, max: 60, step: 0.1, value: belt.innerRadius, onChange: (e) => updateBelt(i, 'innerRadius', e.target.value) })
                        ),
                        h('div', { class: 'field' },
                            h('label', null, `Outer (AU): ${belt.outerRadius}`),
                            h('input', { type: 'range', min: 0.5, max: 80, step: 0.1, value: belt.outerRadius, onChange: (e) => updateBelt(i, 'outerRadius', e.target.value) })
                        ),
                        h('div', { class: 'field' },
                            h('label', null, `Density: ${belt.count}`),
                            h('input', { type: 'range', min: 50, max: 2000, step: 50, value: belt.count, onChange: (e) => updateBelt(i, 'count', e.target.value) })
                        )
                    )
                ),
                h('button', { class: 'btn btn-add', onClick: addBelt }, '+ Add Belt')
            ),

            // Randomizer
            h(Section, { id: 'random-config', title: '\uD83C\uDFB2 Randomize' },
                h('button', { class: 'btn btn-randomize', onClick: doRandomize }, '\u2685 Generate Random System'),
                h('div', { class: 'field', style: 'margin-top:8px' },
                    h('label', null, 'Seed'),
                    h('div', { style: 'display:flex;gap:4px' },
                        h('input', { type: 'text', value: seed, placeholder: '(auto)', onInput: (e) => setSeed(e.target.value) }),
                        h('button', { class: 'btn btn-small', onClick: doRandomize }, 'Apply')
                    )
                ),
                h('div', { class: 'field' },
                    h('label', null, `Complexity: ${COMPLEXITY_LABELS[complexity - 1]}`),
                    h('input', { type: 'range', min: 1, max: 5, value: complexity, onInput: (e) => setComplexity(parseInt(e.target.value)) })
                ),
                h('div', { class: 'field' },
                    h('label', null,
                        h('input', { type: 'checkbox', checked: allowBinary, onChange: (e) => setAllowBinary(e.target.checked) }),
                        ' Allow Binary Stars'
                    )
                ),
                h('div', { class: 'field' },
                    h('label', null,
                        h('input', { type: 'checkbox', checked: allowBelts, onChange: (e) => setAllowBelts(e.target.checked) }),
                        ' Include Asteroid Belts'
                    )
                ),
                randomInfo && h('div', { class: 'random-info' },
                    h('div', null, h('span', { class: 'ri-label' }, 'System:'), ' ', h('span', { class: 'ri-value' }, randomInfo.name)),
                    h('div', null, h('span', { class: 'ri-label' }, 'Star:'), ' ', h('span', { class: 'ri-value' }, `${randomInfo.starType}-type, ${randomInfo.starMass} M\u2609${randomInfo.binary ? ' (binary)' : ''}`)),
                    h('div', null, h('span', { class: 'ri-label' }, 'Planets:'), ' ', h('span', { class: 'ri-value' }, randomInfo.numPlanets)),
                    h('div', null, h('span', { class: 'ri-label' }, 'Moons:'), ' ', h('span', { class: 'ri-value' }, randomInfo.numMoons)),
                    h('div', null, h('span', { class: 'ri-label' }, 'Belts:'), ' ', h('span', { class: 'ri-value' }, randomInfo.numBelts)),
                    h('div', null, h('span', { class: 'ri-label' }, 'Hab. Zone:'), ' ', h('span', { class: 'ri-value' }, randomInfo.habZone))
                )
            ),

            // Presets
            h(Section, { id: 'presets-config', title: '\uD83D\uDCBE Presets' },
                h('button', { class: 'btn btn-preset', onClick: () => loadPresetAndSync('solar') }, 'Solar System'),
                h('button', { class: 'btn btn-preset', onClick: () => loadPresetAndSync('binary') }, 'Binary Star'),
                h('button', { class: 'btn btn-preset', onClick: () => loadPresetAndSync('red-dwarf') }, 'Red Dwarf System'),
                h('button', { class: 'btn btn-preset', onClick: () => loadPresetAndSync('giant') }, 'Blue Giant System')
            )
        ),

        // Planet Modal
        modalIdx !== null && h(PlanetModal, {
            planetIdx: modalIdx,
            onClose: () => setModalIdx(null),
            onSave: handlePlanetSave
        })
    );
}
