import { state } from '../state';
import { parseColor } from '../utils/color';

export function drawRings(x, y, planetR, planet, frontHalf) {
    const { ctx } = state;
    const innerR = planetR * planet.ringInner;
    const outerR = planetR * planet.ringOuter;
    const tilt = 0.3;
    const ringColorHex = planet.ringColor || '#d2be9f';
    const rc = parseColor(ringColorHex);

    ctx.save();

    const bandCount = 5;
    const cassiniPos = 0.55;
    const cassiniWidth = 0.04;

    for (let b = 0; b < bandCount; b++) {
        const t0 = b / bandCount;
        const t1 = (b + 1) / bandCount;
        if (t0 < cassiniPos + cassiniWidth && t1 > cassiniPos - cassiniWidth &&
            Math.abs((t0 + t1) / 2 - cassiniPos) < cassiniWidth) {
            continue;
        }

        const bInner = innerR + (outerR - innerR) * t0;
        const bOuter = innerR + (outerR - innerR) * t1;
        const bandOpacity = (b % 2 === 0) ? 0.45 : 0.3;
        const brightnessShift = (b % 3) * 10 - 10;

        ctx.beginPath();
        if (frontHalf) {
            ctx.ellipse(x, y, bOuter, bOuter * tilt, 0, 0, Math.PI);
            ctx.ellipse(x, y, bInner, bInner * tilt, 0, Math.PI, 0);
        } else {
            ctx.ellipse(x, y, bOuter, bOuter * tilt, 0, Math.PI, Math.PI * 2);
            ctx.ellipse(x, y, bInner, bInner * tilt, 0, Math.PI * 2, Math.PI);
        }
        ctx.closePath();

        const br = Math.min(255, Math.max(0, rc.r + brightnessShift));
        const bg = Math.min(255, Math.max(0, rc.g + brightnessShift));
        const bb = Math.min(255, Math.max(0, rc.b + brightnessShift));
        ctx.fillStyle = `rgba(${br},${bg},${bb},${bandOpacity})`;
        ctx.fill();
    }

    // Fine ring lines
    ctx.globalAlpha = 0.06;
    for (let i = 0; i < 8; i++) {
        const t = i / 8;
        if (Math.abs(t - cassiniPos) < cassiniWidth) continue;
        const rr = innerR + (outerR - innerR) * t;
        ctx.strokeStyle = `rgba(255,255,255,0.8)`;
        ctx.lineWidth = 0.3;
        ctx.beginPath();
        ctx.ellipse(x, y, rr, rr * tilt, 0, frontHalf ? 0 : Math.PI, frontHalf ? Math.PI : Math.PI * 2);
        ctx.stroke();
    }

    // Shadow on rings from planet
    if (frontHalf) {
        ctx.globalAlpha = 0.3;
        ctx.beginPath();
        ctx.ellipse(x, y, planetR * 1.02, planetR * 1.02 * tilt, 0, 0, Math.PI);
        ctx.ellipse(x, y, planetR * 0.98, planetR * 0.98 * tilt, 0, Math.PI, 0);
        ctx.closePath();
        ctx.fillStyle = 'rgba(0,0,0,0.5)';
        ctx.fill();
    }

    ctx.restore();
}
