import { h } from 'preact';
import { useState, useEffect } from 'preact/hooks';
import { state } from '../state';
import { Controls } from './Controls';
import { EditorPanel } from './EditorPanel';

export function App() {
    const [editorOpen, setEditorOpen] = useState(() => window.innerWidth > 768);

    return h('div', null,
        h(Controls, null),
        !editorOpen && h('button', {
            id: 'editor-toggle',
            title: 'Configure System',
            onClick: () => setEditorOpen(true)
        }, '\u2699'),
        h(EditorPanel, { open: editorOpen, onClose: () => setEditorOpen(false) })
    );
}
