import { state } from '../state';

export function drawStarfield() {
    const { ctx, width, height, time, panX, panY, zoomLevel } = state;

    if (!state.starfieldStars) {
        state.starfieldStars = [];
        const starColors = [
            { r: 155, g: 176, b: 255 },
            { r: 170, g: 191, b: 255 },
            { r: 202, g: 215, b: 255 },
            { r: 255, g: 255, b: 255 },
            { r: 255, g: 244, b: 234 },
            { r: 255, g: 224, b: 188 },
            { r: 255, g: 200, b: 150 },
        ];
        for (let i = 0; i < 900; i++) {
            const col = starColors[Math.floor(Math.random() * starColors.length)];
            // depth: 0 = very far (barely moves), 1 = closer (moves more)
            const depth = Math.random();
            state.starfieldStars.push({
                x: Math.random(), y: Math.random(),
                brightness: 0.08 + Math.random() * 0.35,
                size: 0.2 + Math.pow(Math.random(), 4) * 1.8,
                r: col.r, g: col.g, b: col.b,
                twinkleSpeed: 0.3 + Math.random() * 2,
                twinklePhase: Math.random() * Math.PI * 2,
                depth: depth,
                // parallax factor: far stars move 2-5%, close stars move 8-20%
                parallax: 0.02 + depth * 0.18,
            });
        }
    }

    for (const s of state.starfieldStars) {
        const flicker = s.brightness + Math.sin(time * s.twinkleSpeed + s.twinklePhase) * 0.08;
        const alpha = Math.min(0.7, Math.max(0.03, flicker));

        // Parallax offset based on pan and zoom
        const px = panX * s.parallax;
        const py = panY * s.parallax;
        // Slight zoom parallax: closer stars drift outward from center more
        const zoomShift = (zoomLevel - 1) * s.parallax * 0.3;
        const cx = width * 0.5;
        const cy = height * 0.5;

        let sx = s.x * width + px;
        let sy = s.y * height + py;

        // Apply zoom parallax (stars drift from center)
        sx += (sx - cx) * zoomShift;
        sy += (sy - cy) * zoomShift;

        // Wrap around screen edges for seamless scrolling
        sx = ((sx % width) + width) % width;
        sy = ((sy % height) + height) % height;

        ctx.fillStyle = `rgba(${s.r},${s.g},${s.b},${alpha})`;
        ctx.beginPath();
        ctx.arc(sx, sy, s.size, 0, Math.PI * 2);
        ctx.fill();

        // Subtle glow on brighter/larger stars
        if (s.size > 1.2 && alpha > 0.3) {
            ctx.fillStyle = `rgba(${s.r},${s.g},${s.b},${alpha * 0.05})`;
            ctx.beginPath();
            ctx.arc(sx, sy, s.size * 3, 0, Math.PI * 2);
            ctx.fill();
        }
    }
}
