import { uniqueNamesGenerator, adjectives, colors, names } from 'unique-names-generator';

// Custom dictionaries for space-themed naming
const STAR_WORDS = ['Kepler', 'Gliese', 'Trappist', 'Proxima', 'Wolf', 'Ross', 'Tau', 'Sigma', 'Alpha', 'Beta', 'Gamma', 'Delta', 'Epsilon', 'Zeta', 'Eta', 'Theta', 'Omicron', 'Lambda', 'Nova', 'Vega', 'Rigel', 'Sirius', 'Altair', 'Deneb', 'Polaris', 'Castor', 'Mira', 'Astra'];
const STAR_SUFFIXES = ['Prime', 'Major', 'Minor', 'Centauri', 'Orionis', 'Cygni', 'Eridani', 'Draconis', 'Lyrae', 'Aquarii'];
const CELESTIAL_ADJ = ['Ancient', 'Burning', 'Crimson', 'Dark', 'Eternal', 'Frozen', 'Golden', 'Hidden', 'Iron', 'Jade', 'Lost', 'Molten', 'Noble', 'Obsidian', 'Pale', 'Radiant', 'Silent', 'Twilight', 'Veiled', 'Wandering'];
const WORLD_NOUNS = ['Aegis', 'Bastion', 'Caldera', 'Drift', 'Ember', 'Forge', 'Glacier', 'Haven', 'Inferno', 'Jewel', 'Keel', 'Lagoon', 'Mirage', 'Nexus', 'Oasis', 'Pinnacle', 'Quarry', 'Remnant', 'Spire', 'Tempest', 'Umbra', 'Vortex', 'Wisp', 'Zenith'];
const MYTH_NAMES = ['Aegis', 'Boreus', 'Calypso', 'Drakon', 'Erebus', 'Fenrir', 'Gaia', 'Helios', 'Icarus', 'Janus', 'Kronos', 'Lyra', 'Morpheus', 'Nyx', 'Orion', 'Pyrrhus', 'Rhea', 'Selene', 'Titan', 'Vulcan', 'Ymir', 'Zephyr', 'Aether', 'Prometheus', 'Pandora', 'Atlas', 'Hyperion', 'Phoebe', 'Theia', 'Ceres', 'Eos', 'Iris', 'Nemesis', 'Proteus', 'Triton'];
const MOON_WORDS = ['Io', 'Mimas', 'Ariel', 'Nereid', 'Charon', 'Dysnomia', 'Puck', 'Oberon', 'Tethys', 'Dione', 'Portia', 'Cordelia', 'Bianca', 'Neso', 'Sao', 'Laomedeia', 'Iapetus', 'Galatea', 'Larissa', 'Naiad', 'Thalassa', 'Despina', 'Juliet', 'Rosalind', 'Titania', 'Miranda', 'Umbriel', 'Callisto', 'Europa', 'Ganymede'];

/**
 * Convert our seeded rng (0-1 float) to an integer seed for unique-names-generator.
 */
function rngSeed(rng) {
    return Math.floor(rng() * 2147483647);
}

export function generateSystemName(rng) {
    const roll = rng();
    if (roll < 0.4) {
        // Classic catalog style: "Kepler-4821"
        const prefix = STAR_WORDS[Math.floor(rng() * STAR_WORDS.length)];
        const num = Math.floor(rng() * 9000) + 100;
        return `${prefix}-${num}`;
    } else if (roll < 0.65) {
        // Suffix style: "Sigma Draconis"
        const prefix = STAR_WORDS[Math.floor(rng() * STAR_WORDS.length)];
        const suffix = STAR_SUFFIXES[Math.floor(rng() * STAR_SUFFIXES.length)];
        return `${prefix} ${suffix}`;
    } else {
        // Generated style: "Crimson Nexus" or "Golden Vortex"
        return uniqueNamesGenerator({
            dictionaries: [CELESTIAL_ADJ, WORLD_NOUNS],
            separator: ' ',
            seed: rngSeed(rng),
        });
    }
}

export function pickPlanetName(rng, used) {
    const roll = rng();
    if (roll < 0.5) {
        // Mythological name
        const available = MYTH_NAMES.filter(n => !used.has(n));
        if (available.length > 0) {
            const name = available[Math.floor(rng() * available.length)];
            used.add(name);
            return name;
        }
    }
    // Generated two-word name: "adj + color" or "adj + name"
    const name = uniqueNamesGenerator({
        dictionaries: [adjectives, rng() < 0.5 ? colors : names],
        separator: ' ',
        seed: rngSeed(rng),
        style: 'capital',
    });
    if (used.has(name)) return name + ' ' + (Math.floor(rng() * 90) + 10);
    used.add(name);
    return name;
}

export function pickMoonName(rng, used) {
    // Try real moon names first
    const available = MOON_WORDS.filter(n => !used.has(n));
    if (available.length > 0 && rng() < 0.7) {
        const name = available[Math.floor(rng() * available.length)];
        used.add(name);
        return name;
    }
    // Generate a name
    const name = uniqueNamesGenerator({
        dictionaries: [CELESTIAL_ADJ, MOON_WORDS],
        separator: ' ',
        seed: rngSeed(rng),
    });
    if (used.has(name)) return 'Moon-' + Math.floor(rng() * 9000 + 100);
    used.add(name);
    return name;
}
