import { STAR_TYPES } from '../constants';
import { state } from '../state';
import { parseColor, lightenColor, darkenColor } from '../utils/color';
import { sunVisualRadius } from '../utils/physics';

export function drawStar(x, y, starConf, mass) {
    const { ctx, time, zoomLevel } = state;
    const st = STAR_TYPES[starConf.type] || STAR_TYPES.G;
    const r = sunVisualRadius(mass || starConf.mass, state.systemConfig.star.type, zoomLevel);
    const color = st.color;
    const c = parseColor(color);

    // Outer ambient glow
    const ambientGrad = ctx.createRadialGradient(x, y, r * 0.5, x, y, r * 12);
    ambientGrad.addColorStop(0, `rgba(${c.r},${c.g},${c.b},0.06)`);
    ambientGrad.addColorStop(0.3, `rgba(${c.r},${c.g},${c.b},0.03)`);
    ambientGrad.addColorStop(1, `rgba(${c.r},${c.g},${c.b},0)`);
    ctx.fillStyle = ambientGrad;
    ctx.beginPath();
    ctx.arc(x, y, r * 12, 0, Math.PI * 2);
    ctx.fill();

    // Mid glow layers
    for (let i = 6; i >= 1; i--) {
        const radius = r * (1 + i * 2);
        const intensity = 0.12 / (i * 0.8);
        const gradient = ctx.createRadialGradient(x, y, r * 0.3, x, y, radius);
        gradient.addColorStop(0, `rgba(${c.r},${c.g},${c.b},${intensity})`);
        gradient.addColorStop(0.4, `rgba(${c.r},${c.g},${c.b},${intensity * 0.4})`);
        gradient.addColorStop(1, `rgba(${c.r},${c.g},${c.b},0)`);
        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(x, y, radius, 0, Math.PI * 2);
        ctx.fill();
    }

    // Corona
    const coronaGrad = ctx.createRadialGradient(x, y, r * 0.9, x, y, r * 4);
    coronaGrad.addColorStop(0, `rgba(255,255,255,0.25)`);
    coronaGrad.addColorStop(0.1, `rgba(${c.r},${c.g},${c.b},0.35)`);
    coronaGrad.addColorStop(0.4, `rgba(${c.r},${c.g},${c.b},0.12)`);
    coronaGrad.addColorStop(1, `rgba(${c.r},${c.g},${c.b},0)`);
    ctx.fillStyle = coronaGrad;
    ctx.beginPath();
    ctx.arc(x, y, r * 4, 0, Math.PI * 2);
    ctx.fill();

    // Lens flare spikes
    ctx.save();
    ctx.globalAlpha = 0.12;
    const spikeCount = 4;
    for (let i = 0; i < spikeCount; i++) {
        const angle = (i / spikeCount) * Math.PI + time * 0.02;
        const spikeLen = r * (4 + Math.sin(time * 0.5 + i) * 1.5);
        const spikeW = r * 0.15;

        // Forward spike
        ctx.beginPath();
        ctx.moveTo(x + Math.cos(angle) * r * 0.8, y + Math.sin(angle) * r * 0.8);
        ctx.lineTo(x + Math.cos(angle) * spikeLen + Math.cos(angle + Math.PI / 2) * spikeW, y + Math.sin(angle) * spikeLen + Math.sin(angle + Math.PI / 2) * spikeW);
        ctx.lineTo(x + Math.cos(angle) * (spikeLen + r * 0.5), y + Math.sin(angle) * (spikeLen + r * 0.5));
        ctx.lineTo(x + Math.cos(angle) * spikeLen - Math.cos(angle + Math.PI / 2) * spikeW, y + Math.sin(angle) * spikeLen - Math.sin(angle + Math.PI / 2) * spikeW);
        ctx.closePath();
        const spikeGrad = ctx.createLinearGradient(
            x + Math.cos(angle) * r, y + Math.sin(angle) * r,
            x + Math.cos(angle) * spikeLen, y + Math.sin(angle) * spikeLen
        );
        spikeGrad.addColorStop(0, `rgba(${c.r},${c.g},${c.b},0.6)`);
        spikeGrad.addColorStop(0.5, `rgba(${c.r},${c.g},${c.b},0.15)`);
        spikeGrad.addColorStop(1, `rgba(${c.r},${c.g},${c.b},0)`);
        ctx.fillStyle = spikeGrad;
        ctx.fill();

        // Reverse spike
        ctx.beginPath();
        ctx.moveTo(x - Math.cos(angle) * r * 0.8, y - Math.sin(angle) * r * 0.8);
        ctx.lineTo(x - Math.cos(angle) * spikeLen + Math.cos(angle + Math.PI / 2) * spikeW, y - Math.sin(angle) * spikeLen + Math.sin(angle + Math.PI / 2) * spikeW);
        ctx.lineTo(x - Math.cos(angle) * (spikeLen + r * 0.5), y - Math.sin(angle) * (spikeLen + r * 0.5));
        ctx.lineTo(x - Math.cos(angle) * spikeLen - Math.cos(angle + Math.PI / 2) * spikeW, y - Math.sin(angle) * spikeLen - Math.sin(angle + Math.PI / 2) * spikeW);
        ctx.closePath();
        ctx.fillStyle = spikeGrad;
        ctx.fill();
    }
    ctx.restore();

    // Star body
    const bodyGrad = ctx.createRadialGradient(x, y, 0, x, y, r);
    bodyGrad.addColorStop(0, '#ffffff');
    bodyGrad.addColorStop(0.15, '#ffffff');
    bodyGrad.addColorStop(0.35, lightenColor(color, 80));
    bodyGrad.addColorStop(0.65, color);
    bodyGrad.addColorStop(0.85, darkenColor(color, 30));
    bodyGrad.addColorStop(1, darkenColor(color, 70));
    ctx.fillStyle = bodyGrad;
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();

    // Surface granulation
    ctx.save();
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.clip();
    ctx.globalAlpha = 0.08;
    for (let i = 0; i < 20; i++) {
        const cellAngle = (i * 0.314159 + time * 0.05 * (i % 3 === 0 ? 1 : -0.5)) % (Math.PI * 2);
        const cellDist = (i * 7.3 + 3) % r * 0.8;
        const cx2 = x + Math.cos(cellAngle) * cellDist;
        const cy2 = y + Math.sin(cellAngle) * cellDist;
        const cellR = r * (0.08 + 0.06 * Math.sin(i * 2.1 + time * 0.2));
        const cellGrad = ctx.createRadialGradient(cx2, cy2, 0, cx2, cy2, cellR);
        cellGrad.addColorStop(0, lightenColor(color, 30));
        cellGrad.addColorStop(1, darkenColor(color, 20));
        ctx.fillStyle = cellGrad;
        ctx.beginPath();
        ctx.arc(cx2, cy2, cellR, 0, Math.PI * 2);
        ctx.fill();
    }
    // Sunspots
    ctx.globalAlpha = 0.2;
    for (let i = 0; i < 3; i++) {
        const spotAngle = (time * 0.08 + i * 2.1) % (Math.PI * 2);
        const spotDist = r * (0.15 + i * 0.15);
        const sx = x + Math.cos(spotAngle) * spotDist;
        const sy = y + Math.sin(spotAngle) * spotDist;
        const spotR = r * (0.06 + 0.03 * Math.sin(time * 0.15 + i));
        ctx.fillStyle = darkenColor(color, 80);
        ctx.beginPath();
        ctx.arc(sx, sy, spotR, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 0.1;
        ctx.fillStyle = darkenColor(color, 40);
        ctx.beginPath();
        ctx.arc(sx, sy, spotR * 1.8, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 0.2;
    }
    ctx.restore();

    // Bright rim
    ctx.save();
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.strokeStyle = `rgba(255,255,255,0.15)`;
    ctx.lineWidth = 1.5;
    ctx.stroke();
    ctx.restore();

    return r;
}
