import { state } from '../state';
import { lightenColor, darkenColor } from '../utils/color';
import { scaleDistance, scaleRadius } from '../utils/physics';

export function drawMoon(moon, parentX, parentY, t, lightDirX, lightDirY, parentRadius) {
    const { ctx, zoomLevel, showOrbits, showLabels } = state;
    const rawPeriod = Math.pow(moon.orbitRadius * 1000, 1.5) * 0.01;
    // Cap orbital speed: minimum period of 0.15 prevents moons from becoming a blur
    const moonPeriod = Math.max(0.15, rawPeriod);
    const angle = (t / moonPeriod) * Math.PI * 2;
    const moonR = Math.max(1, scaleRadius(moon.radius, zoomLevel) * 0.5);
    // Ensure moons orbit outside the parent planet's visual radius
    const minOrbitPx = (parentRadius || 0) + moonR + 3;
    const orbitPx = Math.max(minOrbitPx, scaleDistance(moon.orbitRadius, zoomLevel) * 8);
    const mx = parentX + Math.cos(angle) * orbitPx;
    const my = parentY + Math.sin(angle) * orbitPx * 0.7;

    if (showOrbits && zoomLevel > 2) {
        ctx.save();
        ctx.strokeStyle = 'rgba(255,255,255,0.04)';
        ctx.lineWidth = 0.3;
        ctx.setLineDash([2, 3]);
        ctx.beginPath();
        ctx.ellipse(parentX, parentY, orbitPx, orbitPx * 0.7, 0, 0, Math.PI * 2);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.restore();
    }

    // Moon body with illumination
    const lx = (lightDirX || 0) * moonR * 0.3;
    const ly = (lightDirY || 0) * moonR * 0.3;
    const moonGrad = ctx.createRadialGradient(mx + lx, my + ly, moonR * 0.1, mx - lx * 0.5, my - ly * 0.5, moonR);
    moonGrad.addColorStop(0, lightenColor(moon.color, 30));
    moonGrad.addColorStop(0.6, moon.color);
    moonGrad.addColorStop(1, darkenColor(moon.color, 60));
    ctx.fillStyle = moonGrad;
    ctx.beginPath();
    ctx.arc(mx, my, moonR, 0, Math.PI * 2);
    ctx.fill();

    if (showLabels && zoomLevel > 3) {
        ctx.save();
        ctx.shadowColor = 'rgba(0,0,0,0.8)';
        ctx.shadowBlur = 2;
        ctx.fillStyle = 'rgba(255,255,255,0.45)';
        ctx.font = '8px sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(moon.name, mx, my - moonR - 3);
        ctx.restore();
    }
}
