export function parseColor(hex) {
    if (hex.startsWith('#')) {
        const r = parseInt(hex.slice(1, 3), 16);
        const g = parseInt(hex.slice(3, 5), 16);
        const b = parseInt(hex.slice(5, 7), 16);
        return { r, g, b };
    }
    return { r: 200, g: 200, b: 200 };
}

export function lightenColor(hex, amount) {
    const c = parseColor(hex);
    return `rgb(${Math.min(255, c.r + amount)},${Math.min(255, c.g + amount)},${Math.min(255, c.b + amount)})`;
}

export function darkenColor(hex, amount) {
    const c = parseColor(hex);
    return `rgb(${Math.max(0, c.r - amount)},${Math.max(0, c.g - amount)},${Math.max(0, c.b - amount)})`;
}

export function hexToRgba(hex, alpha) {
    const c = parseColor(hex);
    return `rgba(${c.r},${c.g},${c.b},${alpha})`;
}

export function hslToHex(h, s, l) {
    s /= 100; l /= 100;
    const a = s * Math.min(l, 1 - l);
    const f = n => {
        const k = (n + h / 30) % 12;
        const color = l - a * Math.max(Math.min(k - 3, 9 - k, 1), -1);
        return Math.round(255 * color).toString(16).padStart(2, '0');
    };
    return `#${f(0)}${f(8)}${f(4)}`;
}

export function randomColor(rng, baseHue, satRange, lightRange) {
    const h = (baseHue + (rng() - 0.5) * 40) % 360;
    const s = satRange[0] + rng() * (satRange[1] - satRange[0]);
    const l = lightRange[0] + rng() * (lightRange[1] - lightRange[0]);
    return hslToHex(h, s, l);
}
