import { PLANET_TYPES } from '../constants';
import { state } from '../state';
import { parseColor, lightenColor, darkenColor } from '../utils/color';
import { scaleDistance, scaleRadius, getOrbitalPosition } from '../utils/physics';
import { drawRings } from './rings';
import { drawMoon } from './moon';

export function drawPlanet(planet, cx, cy, t, starRadius) {
    const { ctx, zoomLevel, showLabels, time } = state;
    const period = Math.pow(planet.semiMajorAxis, 1.5);
    const pos = getOrbitalPosition(planet.semiMajorAxis, planet.eccentricity, period, t);
    const r = scaleRadius(planet.radiusEarth, zoomLevel);

    // Ensure planet orbits outside the star's visual radius
    const rawDist = Math.sqrt(scaleDistance(pos.x, zoomLevel) ** 2 + scaleDistance(pos.y, zoomLevel) ** 2);
    const minDist = (starRadius || 0) + r + 4;
    const distScale = rawDist > 0 && rawDist < minDist ? minDist / rawDist : 1;
    const screenX = cx + scaleDistance(pos.x, zoomLevel) * distScale;
    const screenY = cy + scaleDistance(pos.y, zoomLevel) * distScale;

    // Direction to star (for illumination)
    const dx = cx - screenX;
    const dy = cy - screenY;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
    const lightDirX = dx / dist;
    const lightDirY = dy / dist;
    const lightOffX = lightDirX * r * 0.45;
    const lightOffY = lightDirY * r * 0.45;

    // Rings behind
    if (planet.hasRings) drawRings(screenX, screenY, r, planet, false);

    // Atmosphere glow
    const ptype = PLANET_TYPES[planet.type];
    if (ptype && ptype.atmosphere) {
        const pc = parseColor(planet.color);
        const atmosR = r * 1.25;
        const atmosGrad = ctx.createRadialGradient(
            screenX + lightOffX * 0.5, screenY + lightOffY * 0.5, r * 0.85,
            screenX, screenY, atmosR
        );
        atmosGrad.addColorStop(0, `rgba(${pc.r},${pc.g},${pc.b},0)`);
        atmosGrad.addColorStop(0.5, `rgba(${Math.min(255, pc.r + 40)},${Math.min(255, pc.g + 40)},${Math.min(255, pc.b + 60)},0.2)`);
        atmosGrad.addColorStop(0.8, `rgba(${Math.min(255, pc.r + 60)},${Math.min(255, pc.g + 60)},${Math.min(255, pc.b + 80)},0.15)`);
        atmosGrad.addColorStop(1, `rgba(${pc.r},${pc.g},${pc.b},0)`);
        ctx.fillStyle = atmosGrad;
        ctx.beginPath();
        ctx.arc(screenX, screenY, atmosR, 0, Math.PI * 2);
        ctx.fill();
    }

    // Planet body with illumination
    ctx.save();
    ctx.beginPath();
    ctx.arc(screenX, screenY, r, 0, Math.PI * 2);
    ctx.clip();

    const bodyGrad = ctx.createRadialGradient(
        screenX + lightOffX, screenY + lightOffY, r * 0.1,
        screenX - lightOffX * 0.5, screenY - lightOffY * 0.5, r * 1.1
    );
    bodyGrad.addColorStop(0, lightenColor(planet.color, 50));
    bodyGrad.addColorStop(0.35, lightenColor(planet.color, 15));
    bodyGrad.addColorStop(0.6, planet.color);
    bodyGrad.addColorStop(0.8, darkenColor(planet.color, 50));
    bodyGrad.addColorStop(1, darkenColor(planet.color, 90));
    ctx.fillStyle = bodyGrad;
    ctx.fillRect(screenX - r, screenY - r, r * 2, r * 2);

    // Type-specific surface detail
    drawSurfaceDetail(planet, screenX, screenY, r, lightOffX, lightOffY, time);

    // Shadow overlay
    const shadowGrad = ctx.createRadialGradient(
        screenX + lightOffX * 1.2, screenY + lightOffY * 1.2, r * 0.3,
        screenX - lightOffX * 1.5, screenY - lightOffY * 1.5, r * 1.2
    );
    shadowGrad.addColorStop(0, 'rgba(0,0,0,0)');
    shadowGrad.addColorStop(0.5, 'rgba(0,0,0,0.15)');
    shadowGrad.addColorStop(0.75, 'rgba(0,0,0,0.4)');
    shadowGrad.addColorStop(1, 'rgba(0,0,0,0.65)');
    ctx.fillStyle = shadowGrad;
    ctx.fillRect(screenX - r, screenY - r, r * 2, r * 2);

    ctx.restore();

    // Lava outer glow
    if (planet.type === 'lava') {
        const lavaGlowGrad = ctx.createRadialGradient(screenX, screenY, r * 0.7, screenX, screenY, r * 2.5);
        lavaGlowGrad.addColorStop(0, 'rgba(255,80,0,0.2)');
        lavaGlowGrad.addColorStop(0.5, 'rgba(255,40,0,0.08)');
        lavaGlowGrad.addColorStop(1, 'rgba(255,0,0,0)');
        ctx.fillStyle = lavaGlowGrad;
        ctx.beginPath();
        ctx.arc(screenX, screenY, r * 2.5, 0, Math.PI * 2);
        ctx.fill();
    }

    // Rings front
    if (planet.hasRings) drawRings(screenX, screenY, r, planet, true);

    // Label
    if (showLabels) {
        ctx.save();
        ctx.shadowColor = 'rgba(0,0,0,0.8)';
        ctx.shadowBlur = 3;
        ctx.fillStyle = 'rgba(255,255,255,0.75)';
        ctx.font = '10px sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText(planet.name, screenX, screenY - r - 6);
        ctx.restore();
    }

    // Moons
    if (planet.moons) {
        for (const moon of planet.moons) {
            drawMoon(moon, screenX, screenY, t, lightDirX, lightDirY, r);
        }
    }

    return { name: planet.name, x: screenX, y: screenY, r: Math.max(r, 8), data: planet };
}

function drawSurfaceDetail(planet, screenX, screenY, r, lightOffX, lightOffY, time) {
    const { ctx } = state;

    if (planet.type === 'gas-giant' || planet.type === 'hot-jupiter') {
        ctx.globalAlpha = 0.15;
        const bandCount = 6 + Math.floor(r / 3);
        for (let i = 0; i < bandCount; i++) {
            const bandY = screenY - r + (r * 2 * i) / bandCount;
            const bandH = (r * 2) / bandCount;
            const shift = (i % 2 === 0) ? 15 : -15;
            ctx.fillStyle = (i % 2 === 0)
                ? lightenColor(planet.color, shift)
                : darkenColor(planet.color, Math.abs(shift));
            ctx.fillRect(screenX - r, bandY, r * 2, bandH * 0.7);
        }
        ctx.globalAlpha = 0.12;
        const spotAngle = time * 0.1;
        const spotX = screenX + Math.cos(spotAngle) * r * 0.3;
        const spotY = screenY + r * 0.15;
        ctx.fillStyle = darkenColor(planet.color, 30);
        ctx.beginPath();
        ctx.ellipse(spotX, spotY, r * 0.2, r * 0.12, 0.2, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1;
    }

    if (planet.type === 'ice-giant') {
        ctx.globalAlpha = 0.1;
        for (let i = 0; i < 4; i++) {
            const bandY = screenY - r + (r * 2 * i) / 4;
            ctx.fillStyle = i % 2 === 0 ? lightenColor(planet.color, 20) : darkenColor(planet.color, 15);
            ctx.fillRect(screenX - r, bandY, r * 2, r * 0.3);
        }
        ctx.globalAlpha = 1;
    }

    if (planet.type === 'rocky' || planet.type === 'super-earth') {
        ctx.globalAlpha = 0.06;
        for (let i = 0; i < 8; i++) {
            const cx2 = screenX + (Math.sin(i * 3.7) * r * 0.6);
            const cy2 = screenY + (Math.cos(i * 2.3) * r * 0.6);
            const cr = r * (0.08 + 0.05 * Math.sin(i));
            ctx.fillStyle = darkenColor(planet.color, 40);
            ctx.beginPath();
            ctx.arc(cx2, cy2, cr, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.globalAlpha = 1;
    }

    if (planet.type === 'ice') {
        ctx.globalAlpha = 0.3;
        ctx.fillStyle = '#eef4ff';
        ctx.beginPath();
        ctx.ellipse(screenX, screenY - r * 0.7, r * 0.6, r * 0.25, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(screenX, screenY + r * 0.75, r * 0.5, r * 0.2, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 0.08;
        ctx.strokeStyle = '#aaccee';
        ctx.lineWidth = 0.5;
        for (let i = 0; i < 5; i++) {
            ctx.beginPath();
            ctx.moveTo(screenX + Math.sin(i * 1.3) * r * 0.7, screenY - r * 0.5 + i * r * 0.2);
            ctx.quadraticCurveTo(
                screenX + Math.cos(i * 2.1) * r * 0.3, screenY - r * 0.3 + i * r * 0.2,
                screenX + Math.sin(i * 0.7) * r * 0.5, screenY + i * r * 0.15
            );
            ctx.stroke();
        }
        ctx.globalAlpha = 1;
    }

    if (planet.type === 'ocean') {
        ctx.globalAlpha = 0.15;
        ctx.fillStyle = 'rgba(255,255,255,0.8)';
        for (let i = 0; i < 6; i++) {
            const cloudAngle = (time * 0.05 + i * 1.05) % (Math.PI * 2);
            const cloudX = screenX + Math.cos(cloudAngle) * r * 0.4;
            const cloudY = screenY + Math.sin(cloudAngle + i) * r * 0.5;
            ctx.beginPath();
            ctx.ellipse(cloudX, cloudY, r * 0.25, r * 0.06, cloudAngle * 0.5, 0, Math.PI * 2);
            ctx.fill();
        }
        const specX = screenX + lightOffX * 1.2;
        const specY = screenY + lightOffY * 1.2;
        const specGrad = ctx.createRadialGradient(specX, specY, 0, specX, specY, r * 0.3);
        specGrad.addColorStop(0, 'rgba(255,255,255,0.25)');
        specGrad.addColorStop(1, 'rgba(255,255,255,0)');
        ctx.globalAlpha = 0.4;
        ctx.fillStyle = specGrad;
        ctx.beginPath();
        ctx.arc(specX, specY, r * 0.3, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1;
    }

    if (planet.type === 'lava') {
        ctx.globalAlpha = 0.5;
        ctx.strokeStyle = '#ff4400';
        ctx.lineWidth = 1;
        ctx.shadowColor = '#ff6600';
        ctx.shadowBlur = 4;
        for (let i = 0; i < 7; i++) {
            ctx.beginPath();
            const startA = i * 0.9 + 0.3;
            ctx.moveTo(
                screenX + Math.cos(startA) * r * 0.2,
                screenY + Math.sin(startA) * r * 0.3
            );
            for (let j = 1; j <= 3; j++) {
                ctx.lineTo(
                    screenX + Math.cos(startA + j * 0.4) * r * (0.2 + j * 0.2),
                    screenY + Math.sin(startA + j * 0.5 + i * 0.3) * r * (0.2 + j * 0.15)
                );
            }
            ctx.stroke();
        }
        ctx.shadowBlur = 0;
        ctx.globalAlpha = 0.3;
        for (let i = 0; i < 4; i++) {
            const px = screenX + Math.sin(i * 2.5) * r * 0.4;
            const py = screenY + Math.cos(i * 1.8) * r * 0.35;
            const poolGrad = ctx.createRadialGradient(px, py, 0, px, py, r * 0.12);
            poolGrad.addColorStop(0, '#ffaa00');
            poolGrad.addColorStop(0.5, '#ff4400');
            poolGrad.addColorStop(1, 'rgba(255,50,0,0)');
            ctx.fillStyle = poolGrad;
            ctx.beginPath();
            ctx.arc(px, py, r * 0.12, 0, Math.PI * 2);
            ctx.fill();
        }
        ctx.globalAlpha = 1;
    }
}
