import { h } from 'preact';
import { useState, useEffect } from 'preact/hooks';
import { state } from '../state';

export function InfoPanel({ onZoomTo, onFollow, following }) {
    const [body, setBody] = useState(null);

    useEffect(() => {
        const id = setInterval(() => {
            // Show selected body (persistent) or hovered body
            setBody(state.selectedBody || state.hoveredBody);
        }, 100);
        return () => clearInterval(id);
    }, []);

    if (!body) {
        return h('div', { id: 'info-panel' },
            h('div', { style: 'color:#666' }, 'Hover over a body for info')
        );
    }

    const d = body.data;
    const isFollowing = following === body.name;
    const isPlanet = !!d.radiusEarth;

    return h('div', { id: 'info-panel' },
        h('div', { class: 'planet-name' }, body.name),
        d.radiusEarth ? [
            h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Radius:'), ` ${d.radiusEarth} R\u2295`),
            h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Distance:'), ` ${d.semiMajorAxis} AU`),
            h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Eccentricity:'), ` ${d.eccentricity}`),
            h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Type:'), ` ${d.type}`),
            d.moons && d.moons.length > 0 &&
                h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Moons:'), ` ${d.moons.map(m => m.name).join(', ')}`)
        ] : d.type ? [
            h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Type:'), ` ${d.type}`),
            h('div', { class: 'info-row' }, h('span', { class: 'info-label' }, 'Mass:'), ` ${d.radius}`)
        ] : null,
        h('div', { class: 'info-actions' },
            h('button', {
                class: 'btn btn-small btn-primary',
                onClick: () => onZoomTo && onZoomTo(body)
            }, '\uD83D\uDD0D Zoom To'),
            h('button', {
                class: 'btn btn-small' + (isFollowing ? ' btn-active' : ''),
                onClick: () => onFollow && onFollow(body)
            }, isFollowing ? '\u23F9 Unfollow' : '\uD83C\uDFAF Follow')
        )
    );
}
