import { state } from '../state';
import { scaleDistance, sunVisualRadius } from '../utils/physics';
import { drawStarfield } from './starfield';
import { drawStar } from './star';
import { drawPlanet } from './planet';
import { drawOrbit } from './orbit';
import { drawBelt } from './belt';

export function regenerateBelts() {
    state.beltObjects = state.systemConfig.belts.map(belt => {
        const objects = [];
        for (let i = 0; i < belt.count; i++) {
            objects.push({
                angle: Math.random() * Math.PI * 2,
                dist: belt.innerRadius + Math.random() * (belt.outerRadius - belt.innerRadius),
                size: 0.3 + Math.random() * 1.2,
                speedVar: 0.8 + Math.random() * 0.4,
                eccentricity: Math.random() * 0.15
            });
        }
        return objects;
    });
}

export function resize() {
    const { canvas, ctx } = state;
    const dpr = window.devicePixelRatio || 1;
    state.width = window.innerWidth;
    state.height = window.innerHeight;
    canvas.width = state.width * dpr;
    canvas.height = state.height * dpr;
    canvas.style.width = state.width + 'px';
    canvas.style.height = state.height + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    state.centerX = state.width / 2;
    state.centerY = state.height / 2;
}

export function render() {
    const { ctx, width, height, systemConfig, zoomLevel, showLabels, showOrbits, time } = state;
    ctx.fillStyle = '#000008';
    ctx.fillRect(0, 0, width, height);
    drawStarfield();

    const cx = state.centerX + state.panX;
    const cy = state.centerY + state.panY;
    state.bodies = [];
    let currentStarRadius = 0;

    // Belts
    systemConfig.belts.forEach((belt, i) => {
        if (state.beltObjects[i]) drawBelt(belt, state.beltObjects[i], cx, cy, time);
    });

    // Orbits
    for (const planet of systemConfig.planets) {
        drawOrbit(cx, cy, planet.semiMajorAxis, planet.eccentricity);
    }

    // Stars
    if (systemConfig.binaryStar) {
        const sep = systemConfig.binaryStar.separation || 0.5;
        const binaryPeriod = Math.pow(sep, 1.5) * 0.5;
        const bAngle = (time / binaryPeriod) * Math.PI * 2;
        const m1 = systemConfig.star.mass;
        const m2 = systemConfig.binaryStar.mass;
        const totalM = m1 + m2;
        const r1 = sep * (m2 / totalM);
        const r2 = sep * (m1 / totalM);

        const sx1 = cx + scaleDistance(r1 * Math.cos(bAngle), zoomLevel);
        const sy1 = cy + scaleDistance(r1 * Math.sin(bAngle), zoomLevel);
        const sx2 = cx + scaleDistance(-r2 * Math.cos(bAngle), zoomLevel);
        const sy2 = cy + scaleDistance(-r2 * Math.sin(bAngle), zoomLevel);

        const sr1 = drawStar(sx1, sy1, systemConfig.star, m1);
        const sr2 = drawStar(sx2, sy2, { type: systemConfig.binaryStar.type }, m2);

        if (showOrbits) {
            ctx.strokeStyle = 'rgba(255,255,200,0.06)';
            ctx.lineWidth = 0.5;
            ctx.beginPath();
            ctx.ellipse(cx, cy, scaleDistance(r1, zoomLevel), scaleDistance(r1, zoomLevel) * 0.95, 0, 0, Math.PI * 2);
            ctx.stroke();
            ctx.beginPath();
            ctx.ellipse(cx, cy, scaleDistance(r2, zoomLevel), scaleDistance(r2, zoomLevel) * 0.95, 0, 0, Math.PI * 2);
            ctx.stroke();
        }

        if (showLabels) {
            ctx.fillStyle = 'rgba(255,255,255,0.6)';
            ctx.font = '10px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('Star A', sx1, sy1 - sr1 - 5);
            ctx.fillText('Star B', sx2, sy2 - sr2 - 5);
        }

        state.bodies.push({ name: 'Star A (' + systemConfig.star.type + ')', x: sx1, y: sy1, r: sr1, data: { radius: systemConfig.star.mass + ' M\u2609', type: systemConfig.star.type } });
        state.bodies.push({ name: 'Star B (' + systemConfig.binaryStar.type + ')', x: sx2, y: sy2, r: sr2, data: { radius: systemConfig.binaryStar.mass + ' M\u2609', type: systemConfig.binaryStar.type } });
        currentStarRadius = Math.max(sr1, sr2);
    } else {
        const sr = drawStar(cx, cy, systemConfig.star, systemConfig.star.mass);
        if (showLabels) {
            ctx.fillStyle = 'rgba(255,255,255,0.6)';
            ctx.font = '10px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('Star (' + systemConfig.star.type + ')', cx, cy - sr - 5);
        }
        state.bodies.push({ name: 'Star (' + systemConfig.star.type + ')', x: cx, y: cy, r: sr, data: { radius: systemConfig.star.mass + ' M\u2609', type: systemConfig.star.type } });
        currentStarRadius = sr;
    }

    // Planets
    for (const planet of systemConfig.planets) {
        const body = drawPlanet(planet, cx, cy, time, currentStarRadius);
        state.bodies.push(body);
    }

    // Follow target: keep followed planet centered
    if (state.followTarget) {
        const target = state.bodies.find(b => b.name === state.followTarget);
        if (target) {
            state.panX = state.centerX - target.x + state.panX;
            state.panY = state.centerY - target.y + state.panY;
        }
    }

    // Bounding box: clamp pan so the system stays in the viewport
    clampPan();

    state.time += 0.001 * state.speedMultiplier;
    requestAnimationFrame(render);
}

function clampPan() {
    const { systemConfig, zoomLevel, centerX, centerY, width, height } = state;
    // Find the outermost orbit distance in pixels
    let maxAU = 1;
    for (const planet of systemConfig.planets) {
        const dist = planet.semiMajorAxis * (1 + (planet.eccentricity || 0));
        if (dist > maxAU) maxAU = dist;
    }
    const maxPx = scaleDistance(maxAU, zoomLevel) + 50;
    // The system center (centerX + panX, centerY + panY) must stay so that
    // at least part of the system is visible
    const margin = Math.min(maxPx, Math.min(width, height) * 0.4);
    const minPanX = -maxPx - centerX + margin;
    const maxPanX = maxPx + width - centerX - margin;
    const minPanY = -maxPx - centerY + margin;
    const maxPanY = maxPx + height - centerY - margin;
    state.panX = Math.max(minPanX, Math.min(maxPanX, state.panX));
    state.panY = Math.max(minPanY, Math.min(maxPanY, state.panY));
}

export function saveScreenshot() {
    const link = document.createElement('a');
    link.download = 'solar-system-' + Date.now() + '.jpg';
    link.href = state.canvas.toDataURL('image/jpeg', 0.92);
    link.click();
}
